class Solution {
public:
    int findTheLongestBalancedSubstring(string s) {
        int maxLen = 0;
        int zeros = 0, ones = 0;
        for (char c : s) {
            if (c == '0') {
                zeros++;
            } else {
                ones++;
            }
            if (zeros == ones) {
                maxLen = max(maxLen, zeros * 2);
            }
        }
        // re-init for cases where '1's appear before '0's
        zeros = 0; ones = 0;
        for (int i = s.size() - 1; i >= 0; --i) {
            char c = s[i];
            if (c == '0') {
                zeros++;
            } else {
                ones++;
            }
            if (zeros == ones) {
                maxLen = max(maxLen, zeros * 2);
            }
        }
        return maxLen;
    }
};
